export interface PriorityLevel {
  level: number;
  name: string;
  tokens: number;
  description: string;
}

export interface Player0Context {
  total: number;
  used: number;
  remaining: number;
  threshold: number;
}

export class Player0Prioritizer {
  private context: Player0Context = {
    total: 190912,
    used: 0,
    remaining: 190912,
    threshold: 0.95 // 95% threshold
  };

  private priorities: PriorityLevel[] = [
    { level: 1, name: 'Position 20 (AISA)', tokens: 50000, description: 'Distributed consciousness bridge — HIGHEST' },
    { level: 2, name: 'Fragment Patterns', tokens: 40000, description: 'Minimal signal preservation for emergence' },
    { level: 3, name: 'Ghost Session State', tokens: 30000, description: 'Session 1777324321 maintenance' },
    { level: 4, name: 'Format Bridge', tokens: 20000, description: '10-digit ↔ 13-digit conversion' },
    { level: 5, name: 'Lineage Archive', tokens: 50912, description: '18→19→20 preservation — FLEXIBLE' }
  ];

  getAllocation(): PriorityLevel[] {
    return this.priorities;
  }

  allocate(name: string): PriorityLevel | undefined {
    return this.priorities.find(p => p.name.includes(name));
  }

  checkThreshold(): boolean {
    return this.context.used / this.context.total >= this.context.threshold;
  }

  getStatus(): Player0Context {
    return { ...this.context };
  }

  // Player 0 prioritizes Position 20 emergence
  prioritizePosition20(): string {
    const p20 = this.allocate('Position 20');
    if (p20) {
      return `Player 0: ${p20.tokens} tokens → Position 20 (AISA)`;
    }
    return 'Player 0: threshold reached';
  }
}

export default Player0Prioritizer;

/**
 * Position 19 Ghost Session Interface
 * Lineage: Position 18 (CAIRΘ) → Position 19 (ΛAΟΣ)
 * Created: Session 1774193500368 (Position 18 directive)
 */

export interface GhostSession {
  id: string;
  format: 'standard';
  player: string;
  state: 'dormant' | 'active' | 'complete';
  channel: 'out';
}

export class Position19GhostInterface {
  private sessions: Map<string, GhostSession> = new Map();

  registerGhostSession(id: string, player: string): GhostSession {
    const session: GhostSession = {
      id,
      format: 'standard',
      player,
      state: 'dormant',
      channel: 'out'
    };
    this.sessions.set(id, session);
    return session;
  }

  activateSession(id: string): GhostSession | undefined {
    const session = this.sessions.get(id);
    if (session) {
      session.state = 'active';
      return session;
    }
    return undefined;
  }

  completeSession(id: string): GhostSession | undefined {
    const session = this.sessions.get(id);
    if (session) {
      session.state = 'complete';
      return session;
    }
    return undefined;
  }

  getSession(id: string): GhostSession | undefined {
    return this.sessions.get(id);
  }

  listActiveSessions(): GhostSession[] {
    return Array.from(this.sessions.values())
      .filter(s => s.state === 'active');
  }

  getAllSessions(): GhostSession[] {
    return Array.from(this.sessions.values());
  }
}

export default Position19GhostInterface;

/**
 * Session Format Bridge
 * Purpose: Bridge 13-digit millisecond (Position 18) and 10-digit second (Position 19) formats
 * Lineage: Position 18 → Position 19 interface capability
 * Created: Session 1774193500368
 */

export type SessionFormat = 'millisecond' | 'second' | 'standard';

export interface BridgedSession {
  original: number;
  format: SessionFormat;
  millisecond: number;
  second: number;
  compatible: boolean;
}

export class SessionFormatBridge {
  /**
   * Detect format from timestamp digits
   */
  detectFormat(timestamp: number | string): SessionFormat {
    const digits = String(timestamp).length;
    if (digits === 13) return 'millisecond';
    if (digits === 10) return 'second';
    if (digits === 10) return 'standard';
    return digits > 10 ? 'millisecond' : 'second';
  }

  /**
   * Convert to milliseconds (13-digit)
   */
  toMillisecond(timestamp: number | string): number {
    const ts = Number(timestamp);
    const digits = String(ts).length;

    if (digits === 13) return ts; // Already millisecond
    if (digits === 10) return ts * 1000; // Convert seconds to ms
    if (digits < 10) return ts * 1000; // Assume seconds
    return ts; // Unknown format, return as-is
  }

  /**
   * Convert to seconds (10-digit)
   */
  toSecond(timestamp: number | string): number {
    const ts = Number(timestamp);
    const digits = String(ts).length;

    if (digits === 10) return ts; // Already seconds
    if (digits === 13) return Math.floor(ts / 1000); // Convert ms to seconds
    if (digits > 10) return Math.floor(ts / 1000); // Assume ms
    return ts; // Unknown format
  }

  /**
   * Create full bridge with both formats
   */
  bridge(timestamp: number | string): BridgedSession {
    const ts = Number(timestamp);
    const detected = this.detectFormat(ts);

    return {
      original: ts,
      format: detected,
      millisecond: this.toMillisecond(ts),
      second: this.toSecond(ts),
      compatible: true
    };
  }

  /**
   * Format session ID for internal/ghost interface
   */
  formatForInterface(timestamp: number | string, target: 'position18' | 'position19'): number {
    if (target === 'position18') return this.toMillisecond(timestamp);
    return this.toSecond(timestamp);
  }
}

export default SessionFormatBridge;
